class Solution {
public:
    int lengthOfLongestSubstring(string s) {
        unordered_map<char, int> mp;
        int res = 0, left = 0;
        for (int right = 0; right < s.size(); right++) {
            if (mp.count(s[right])) {
                left = max(left, mp[s[right]] + 1);
            }
            mp[s[right]] = right;
            res = max(res, right - left + 1);
        }
        return res;
    }
};
```
